    @Test
    fun `genererBruttoPdfPayload escaper ampersand i rich text for alle seksjoner`() {
        every { seksjonRepository.hentPdfGrunnlag(any(), any()) } returns
            listOf(
                """
                {
                  "navn": "Seksjon 1",
                  "spørsmål": [
                    {
                      "label": "<strong>Gekki & Gekko</strong>",
                      "description": "<i>Hei & hå</i>",
                      "svar": "ja & nei"
                    }
                  ]
                }
                """.trimIndent(),
                """
                {
                  "navn": "Seksjon 2",
                  "spørsmål": [
                    {
                      "label": "<strong>Andre & tredje</strong>",
                      "svar": "ja"
                    }
                  ]
                }
                """.trimIndent(),
                """
                {
                  "navn": "Seksjon 3",
                  "spørsmål": [
                    {
                        "id": "reistTilbakeTilBostedslandet",
                        "type": "envalg",
                        "label": "Har du reist tilbake til & bostedslandet ditt etter at du ble arbeidsledig eller permittert?",
                        "description": "Hvis du bor i et EØS-land & jobber i et annet, er du en EØS-pendler. Det er egne regler for hvor du skal søke om penger hvis du blir arbeidsledig eller permittert og du har tilknytning til flere EØS-land.<br/><br/>Hvilket land du skal søke om penger fra avhenger av<ul><li>hvilket land du sist jobbet i</li><li>hvilket land du bor i</li><li>om du er permittert eller delvis arbeidsledig, eller om du er helt arbeidsledig</li></ul>Er du usikker på hva du skal svare, kan du lese <a href='https://nav.no/dagpenger#eos'>mer om hvor du skal søke penger fra</a>.",
                        "options": [
                            {
                                "value": "ja &",
                                "label": "Ja &"
                            },
                            {
                                "value": "nei &",
                                "label": "Nei &"
                            }
                        ],
                        "svar": "nei &"
                    }
                  ]
                }
                """.trimIndent(),
            )

        val bruttoPdfPayload = pdfPayloadService.genererBruttoPdfPayload(randomUUID(), ident)

        bruttoPdfPayload shouldContain "Gekki &amp; Gekko" // label still uses default FreeMarker escaping
        bruttoPdfPayload shouldContain "Hei &amp; hå" // description uses ?no_esc, so only one level of escaping
        bruttoPdfPayload shouldContain "Andre &amp; tredje"
        bruttoPdfPayload shouldContain "ja &amp; nei" // svar should not be normalized
    }

    @Test
    fun `genererBruttoPdfPayload fjerner utstøttet html men beholder tekst`() {
        every { seksjonRepository.hentPdfGrunnlag(any(), any()) } returns
            listOf(
                """
                {
                  "navn": "Dokumentasjon",
                  "spørsmål": [
                    {
                      "label": "<strong>Arbeidsavtale - test</strong>",
                      "description": "<div style=\"--gap:8\" class=\"aksel-stack\"><p class=\"aksel-body-short\">Du har lagt til et arbeidsforhold.</p><div class=\"aksel-read-more\"><button type=\"button\" class=\"aksel-read-more__button\"><svg xmlns=\"http://www.w3.org/2000/svg\" width=\"1em\" height=\"1em\"><path d=\"M5.97 9.47\"></path></svg><span>Dette må dokumentasjonen inneholde</span></button><div class=\"aksel-read-more__content\"><p class=\"aksel-body-short\">Arbeidsavtalen må inneholde</p><ul role=\"list\"><li class=\"aksel-list__item\"><div>datoen du startet</div></li><li class=\"aksel-list__item\"><div>stillingsprosent</div></li></ul></div></div></div>",
                      "svar": "ok"
                    }
                  ]
                }
                """.trimIndent(),
            )

        val bruttoPdfPayload = pdfPayloadService.genererBruttoPdfPayload(randomUUID(), ident)

        // Text content is preserved
        bruttoPdfPayload shouldContain "Du har lagt til et arbeidsforhold."
        bruttoPdfPayload shouldContain "Arbeidsavtalen må inneholde"
        bruttoPdfPayload shouldContain "datoen du startet"
        bruttoPdfPayload shouldContain "stillingsprosent"

        // Unsupported tags are stripped
        bruttoPdfPayload shouldNotContain "<button"
        bruttoPdfPayload shouldNotContain "<svg"
        bruttoPdfPayload shouldNotContain "aksel-stack"
        bruttoPdfPayload shouldNotContain "aksel-read-more"
        bruttoPdfPayload shouldNotContain "aksel-body-short"
        bruttoPdfPayload shouldNotContain "style=\"--gap"

        // Safe tags are preserved
        bruttoPdfPayload shouldContain "<p>"
        bruttoPdfPayload shouldContain "<ul>"
        bruttoPdfPayload shouldContain "<li>"
    }

    @Test
    fun `genererBruttoPdfPayload beholder trygge lenker og fjerner usikre`() {
        every { seksjonRepository.hentPdfGrunnlag(any(), any()) } returns
            listOf(
                """
                {
                  "navn": "Test",
                  "spørsmål": [
                    {
                      "label": "Test",
                      "description": "<a href='https://nav.no/info'>Trygg lenke</a> og <a href='javascript:alert(1)'>Utrygg lenke</a>",
                      "svar": "ok"
                    }
                  ]
                }
                """.trimIndent(),
            )

        val bruttoPdfPayload = pdfPayloadService.genererBruttoPdfPayload(randomUUID(), ident)

        bruttoPdfPayload shouldContain """<a href="https://nav.no/info">Trygg lenke</a>"""
        bruttoPdfPayload shouldContain "<a>Utrygg lenke</a>"
        bruttoPdfPayload shouldNotContain "javascript:"
    }

    @Test
    fun `genererBruttoPdfPayload escaper ampersand i rich text for alle seksjoner 2`() {
        every { seksjonRepository.hentPdfGrunnlag(any(), any()) } returns
            listOf(
                """
                {"navn":"Startside","spørsmål":[{"id":"5b3c81e0779d","type":"forklarendeTekst","label":"<p>Dagpenger er økonomisk støtte på veien tilbake til arbeid. For å ha rett til dagpenger, må du fylle noen krav. <a href=\"https://www.nav.no/dagpenger\">Her kan du lese om du har rett til dagpenger.</a></p>"},{"id":"740062f4ecea","type":"headingTekst","label":"Når du søker dagpenger må du:","størrelse":"medium","nivå":"2"},{"id":"d05723eedba2","type":"forklarendeTekst","label":"<ul><li><strong>Være registrert som arbeidssøker og sende meldekort hver 14. dag</strong><br/>Du må være registrert som arbeidssøker og sende meldekort i hele perioden du mottar dagpenger, også mens du venter på svar på søknaden.<br/><br/>På hvert meldekort bekrefter du at du fortsatt vil være registrert som arbeidssøker, og du gir informasjon til Nav for at vi skal kunne beregne hvor mye du skal få i dagpenger.</li></ul>"},{"id":"bc13a99cf379","type":"forklarendeTekst","label":"<ul><li><strong>Gi beskjed hvis situasjonen din endrer seg<br/></strong>I tillegg til å sende meldekort er det viktig at du gir oss beskjed hvis situasjonen din endrer seg, for eksempel hvis du er tilbake i jobb, er syk eller oppholder deg i utlandet.</li></ul>"},{"id":"8466e0cc54e6","type":"forklarendeTekst","label":"<ul><li><strong>Være reell jobbsøker</strong><br/>I søknaden må du svare på spørsmål om du er frisk nok til å jobbe og om du kan ta alle typer arbeid hvor som helst i Norge. Du må i tillegg være aktiv jobbsøker og takke ja til arbeidsmarkedstiltak.</li></ul>"},{"id":"3ba5c9008c10","type":"headingTekst","label":"Slik søker du","størrelse":"medium","nivå":"2"},{"id":"71743173dee9","type":"forklarendeTekst","label":"<p>I søknaden stiller vi kun spørsmål som er relevante i din situasjon. Antall spørsmål og tiden det tar å søke vil derfor kunne variere. De fleste bruker 20-30 minutter.</p>"},{"id":"54ee9db2a1f3","type":"forklarendeTekst","label":"<p>Noen av opplysningene du gir i søknaden må du dokumentere. Du får beskjed underveis i søknaden om hvilken dokumentasjon du må sende inn.<br/>Du kan ta pauser når du fyller ut søknaden. Vi lagrer søknaden i opptil sju dager mens du fyller ut.</p>"},{"id":"8c5fc0180d6b","type":"headingTekst","label":"Vi vil hente og bruke informasjon om deg","størrelse":"medium","nivå":"2"},{"id":"81df538e1a55","type":"forklarendeTekst","label":"<p>I tillegg til informasjonen du oppgir i søknaden, henter vi inn informasjon om deg for å avgjøre om du har rett til dagpenger. Vi deler også noe av informasjonen din med andre offentlige virksomheter.</p>"},{"id":"332384857777","type":"lesMer","label":"Les mer om hvordan vi henter og deler informasjon om deg","description":"<p>For å vurdere om du har rett til dagpenger etter folketrygdloven kapittel 4, må vi hente inn informasjon om deg.</p><p>Vi henter:</p><ul><li>personinformasjon, opplysninger om bosted og familieforhold fra folkeregisteret</li><li>inntektsinformasjon og skattekort fra Skatteetaten</li><li>opplysninger om arbeidsforhold fra arbeidsgiver- og arbeidstakerregisteret. Vi kan også hente informasjon om arbeidsforhold og trygdeperioder fra myndighetene i andre EØS-land</li><li>informasjon om egen næring fra Brønnøysundregisteret</li></ul><p>Vi kan også hente inn tidligere opplysninger du har gitt oss, eller opplysninger du gir oss i andre sammenhenger, hvis det er relevant og nødvendig.</p><p>Vi deler:</p><ul><li>beløpet du får i dagpenger med Skatteetaten og Statistisk sentralbyrå gjennom A-ordningen</li><li>informasjon med Statens lånekasse for utdanning </li><li>utbetalinger fra NAV til offentlige pensjonskasser</li></ul><p>Vi kan også bruke opplysningene dine i andre sammenhenger i NAV, hvis det er relevant og nødvendig.</p><p><a href=\"https://www.nav.no/personvernerklaering\">Les mer om hvordan Nav behandler personopplysninger</a></p>"},{"id":"13f20750c27f","type":"headingTekst","label":"Automatisk behandling","størrelse":"medium","nivå":"2"},{"id":"3a6e0dddbc88","type":"forklarendeTekst","label":"<p>Noen søknader vil bli behandlet automatisk. Det betyr at du får svar på søknaden uten at en saksbehandler har sett på saken din. Hvis du er uenig i svaret du får, kan du klage. <a href=\"https://www.nav.no/personvernerklaering#dine-rettigheter\">Les mer om automatisk behandling og dine rettigheter</a></p>"},{"id":"bc44acf3c7a9","type":"forklarendeTekst","label":"<p>Vi henter inntekten din automatisk fra Skatteetaten. Hvis du har jobbet for en utenlandsk arbeidsgiver eller ved en ambassade, kan det være lurt å sjekke at inntekten din er riktig på Skatteetaten.no.</p>"},{"id":"d69aa50c48e2","type":"headingTekst","label":"Vi trenger riktige opplysninger for å vurdere om du har rett til dagpenger","størrelse":"medium","nivå":"2"},{"id":"8e1cb4883cb0","type":"forklarendeTekst","label":"<p>Det er viktig at du gir oss riktige opplysninger slik at vi kan behandle saken din. <a href=\"https://www.nav.no/endringer\">Les mer om viktigheten av å gi riktige opplysninger.</a></p>"},{"id":"bekreftVilkår","type":"envalg","label":"Jeg bekrefter at jeg vil svare så riktig som jeg kan","options":[{"value":"ja","label":"Ja"},{"value":"nei","label":"Nei"}],"svar":"ja"}]}
                """.trimIndent(),
                """{"navn":"Personalia","spørsmål":[{"id":"fornavnFraPdl","type":"registeropplysning","label":"Fornavn","svar":"FIRKANTET"},{"id":"etternavnFraPdl","type":"registeropplysning","label":"Etternavn","svar":"JEGER"},{"id":"fødselsnummerFraPdl","type":"registeropplysning","label":"Fødselsnummer","svar":"16847195324"},{"id":"adresselinje1FraPdl","type":"registeropplysning","label":"Adresselinje 1","svar":"Kubjelleveien 8A"},{"id":"postnummerFraPdl","type":"registeropplysning","label":"Postnummer","svar":"1570"},{"id":"poststedFraPdl","type":"registeropplysning","label":"Poststed","svar":"Dilling"},{"id":"landkodeFraPdl","type":"registeropplysning","label":"Landkode","svar":"NO"},{"id":"landFraPdl","type":"registeropplysning","label":"Land","svar":"NORGE"},{"id":"personaliaBostedslandForklarendeTekst","type":"forklarendeTekst","description":"<h3>Bostedsland</h3>"},{"id":"folkeregistrertAdresseErNorgeStemmerDet","type":"envalg","label":"Du er folkeregistrert i Norge. Er Norge bostedslandet ditt?","description":"Bostedslandet ditt er det landet du eier eller leier bolig i og tilbringer mesteparten av tiden din, også når du ikke jobber.","options":[{"value":"ja","label":"Ja, Norge er bostedslandet mitt"},{"value":"nei","label":"Nei, Norge er ikke bostedslandet mitt"}],"svar":"ja"}]}"""
                    .trimIndent(),
                """{"navn":"Din situasjon","spørsmål":[{"id":"harDuMottattDagpengerFraNavILøpetAvDeSiste52Ukene","type":"envalg","label":"Har du mottatt dagpenger fra Nav i løpet av de siste 52 ukene?","options":[{"value":"ja","label":"Ja"},{"value":"nei","label":"Nei"},{"value":"vetikke","label":"Vet ikke"}],"svar":"nei"},{"id":"hvilkenDatoSøkerDuDagpengerFra","type":"dato","label":"Hvilken dato søker du dagpenger fra?","description":"Du kan få dagpenger fra første dag du er helt eller delvis arbeidsledig eller permittert og tidligst fra den dagen du sender inn søknaden. Datoen du søker om dagpenger fra har betydning for beregning av dagpengene dine.","svar":"13. mai 2026"},{"id":"hvilkenDatoSøkerDuDagpengerFraLesMer","type":"lesMer","label":"Dato, inntekt og beregning av dagpenger","description":"<p>Vi beregner hvor mye du kan få i dagpenger basert på hva du har hatt i inntekt de siste 12 eller 36 månedene. Ønsker du å få med siste måneds inntekt, må du søke dagpenger tidligst fra den 6. i måneden etter. Årsaken er at vi får melding om inntekten din fra Skatteetaten den 5. i måneden. Hvis den 5. er en helg eller helligdag, får vi melding om inntekten din neste virkedag.</p><p><strong>Eksempel:</strong><br/>Hvis du søker om dagpenger fra 1. til 5. mars, vil januar bli siste måned med inntekt som tas med i beregningen av dagpengene dine. Søker du om dagpenger fra 6. mars, vil februar bli siste måned med inntekt som tas med i beregningen.</p><p>Hvis 5. mars er en lørdag, får vi inn inntekten din mandag 7. mars. Da må du søke dagpenger fra tirsdag 8. mars hvis du vil ha med inntekten din fra februar i beregningen.</p>"}]}"""
