value":"ALA","label":"Åland"}],"svar":"NOR"},{"id":"hvordanHarDetteArbeidsforholdetEndretSeg","type":"envalg","label":"Hvordan har dette arbeidsforholdet endret seg?","options":[{"value":"arbeidsgiverenMinHarSagtMegOpp","label":"Arbeidsgiveren min har sagt meg opp"},{"value":"jegHarSagtOppSelv","label":"Jeg har sagt opp selv"},{"value":"jegHarFåttAvskjed","label":"Jeg har fått avskjed"},{"value":"kontraktenErUtgått","label":"Kontrakten er utgått"},{"value":"arbeidstidenErRedusert","label":"Arbeidstiden er redusert"},{"value":"arbeidsgiverErKonkurs","label":"Arbeidsgiver er konkurs"},{"value":"jegErPermittert","label":"Jeg er permittert"},{"value":"arbeidsforholdetErIkkeEndret","label":"Arbeidsforholdet er ikke endret"}],"svar":"jegHarFåttAvskjed"},{"id":"jegHarFåttAvskjedVarighetPåArbeidsforholdetFraDato","type":"periodeFra","label":"Fra dato","svar":"27. mai 2026"},{"id":"jegHarFåttAvskjedVarighetPåArbeidsforholdetTilDato","type":"periodeTil","label":"Til dato","svar":"29. mai 2026"},{"id":"jegHarFåttAvskjedInformasjonskort","type":"informasjonskort","label":"Informasjon","description":"<p>Hvis du har fått avskjed fra arbeidsgiver, må vi vite hvorfor.</p><p>Avskjed betyr at du må slutte i jobben din umiddelbart, uten oppsigelsestid.</p><p>Du må dokumentere eller beskrive grunnen og datoen for avskjeden. Dette kan for eksempel stå i avskjedsbrevet eller i møtereferat.</p><p>Har du fått avskjed vil du normalt ikke få utbetalt dagpenger i 18 uker.</p><p>Det er Nav som vurderer om grunnen til avskjeden får betydning for utbetalingen din.</p><p>Du må være registrert som arbeidssøker og sende meldekort i ventetiden.</p>"},{"id":"jegHarFåttAvskjedArbeidsavtaleDokumentasjonskravindikator","type":"dokumentasjonskravindikator","label":"Arbeidsavtale"},{"id":"jegHarFåttAvskjedDokumentasjonskravindikator","type":"dokumentasjonskravindikator","label":"Avskjedigelse"},{"id":"jegHarFåttAvskjedHvaVarÅrsaken","type":"langTekst","label":"Hva var årsaken til at du ble avskjediget?","svar":"asd"},{"id":"harDuJobbetSkiftTurnusEllerRotasjon","type":"envalg","label":"Har du jobbet skift, turnus eller rotasjon?","description":"<p>Skift eller turnus kan være når du har avtale om å arbeide ulike tider i ulike uker, som for eksempel dagtid en uke og kveldstid en uke, eller har fri hver tredje helg.</p><p>En rotasjon er for eksempel at du arbeider to uker og har fri i to uker.</p>","options":[{"value":"skiftEllerTurns","label":"Ja, jeg har jobbet skift eller turnus"},{"value":"rotasjon","label":"Ja, jeg har jobbet rotasjon"},{"value":"hverkenSkiftTurnusEllerRotasjon","label":"Nei, ingen av delene"}],"svar":"rotasjon"},{"id":"harDuJobbetSkiftTurnusEllerRotasjonLesMer","type":"lesMer","label":"Grunnen til at vi spør om dette","description":"<p>Vi må vite hvilken arbeidstidsordning du har for å gi deg dagpenger fra riktig dato.</p>"},{"id":"jegHarJobbetRotasjonDokumentasjonskravindikator","type":"dokumentasjonskravindikator","label":"Dokumentasjon av rotasjonsordningen og den siste arbeidsperioden din"},{"id":"hvilkenTypeRotasjonsordningJobbetDu","type":"envalg","label":"Hvilke type rotasjonsordning jobbet du?","options":[{"value":"2-4-rotasjon","label":"2:4"},{"value":"2-3-rotasjon","label":"2:3"},{"value":"1-1-rotasjon","label":"1:1"},{"value":"annenRotasjon","label":"Annen rotasjon"}],"svar":"2-3-rotasjon"},{"id":"oppgiSisteArbeidsperiodeIDenSisteRotasjonenDinFraDato","type":"periodeFra","label":"Fra dato","svar":"28. mai 2026"},{"id":"oppgiSisteArbeidsperiodeIDenSisteRotasjonenDinTilDato","type":"periodeTil","label":"Til dato","svar":"28. mai 2026"}]]}"""
